(function($){'use strict';const synclyMembership=window.syncly_membership_admin_js_data||{};const SynclyMembershipAdmin={init:function(){this.initSelect2();this.initRestrictionType()},initSelect2:function(){const $tagsSelect=$('#ghl_required_tags');if($tagsSelect.length===0){return}
var allTags=(typeof synclyMembership!=='undefined'&&synclyMembership.tags)?synclyMembership.tags:[];var selectedIds=$tagsSelect.find('option').map(function(){return $(this).val()}).get();allTags.forEach(function(tag){var label=String(tag.name||tag.id||'');if(label&&selectedIds.indexOf(label)===-1){$tagsSelect.append(new Option(label,label,!1,!1))}});$tagsSelect.select2({tags:!0,tokenSeparators:[','],placeholder:$tagsSelect.data('placeholder'),closeOnSelect:!1,allowClear:!0,width:'100%',scrollAfterSelect:!1})},initRestrictionType:function(){const $restrictionType=$('#ghl_restriction_type');const $tagsContainer=$('#ghl-tags-container');const $redirectContainer=$('#ghl-redirect-container');if($restrictionType.length===0){return}
$restrictionType.on('change',function(){const value=$(this).val();if(value){$tagsContainer.slideDown(200);$redirectContainer.slideDown(200)}else{$tagsContainer.slideUp(200);$redirectContainer.slideUp(200)}})}};$(document).ready(function(){SynclyMembershipAdmin.init()})})(jQuery)